INSERT INTO exercises (name, technique, common_mistakes, easier_modification, harder_modification, rest_seconds) VALUES
  ('Растяжка квадрицепсов стоя', 'Стойте прямо, согните одну ногу и возьмитесь за стопу рукой. Подтяните пятку к ягодице. Держите колени вместе.', 'Наклон корпуса вперёд, колено уходит в сторону', 'Держитесь за стену для баланса', 'Добавьте наклон корпуса назад', 30),
  ('Растяжка задней поверхности бедра', 'Сядьте на пол, вытяните одну ногу. Наклонитесь вперёд, тянитесь руками к стопе. Спина прямая.', 'Округление спины, рывки', 'Используйте ремень для захвата стопы', 'Поднимите ногу на возвышение', 30),
  ('Кошка-корова', 'Встаньте на четвереньки. На вдохе прогните спину вниз, на выдохе округлите спину вверх. Движение плавное.', 'Слишком быстрые движения, зажатая шея', 'Уменьшите амплитуду движения', 'Добавьте задержку в каждой позиции на 3 секунды', 20),
  ('Мостик (ягодичный)', 'Лягте на спину, согните ноги. Поднимите таз вверх, сжимая ягодицы. Задержитесь наверху.', 'Переразгибание в пояснице, отрыв лопаток', 'Уменьшите амплитуду подъёма', 'Выполняйте на одной ноге', 45),
  ('Планка на локтях', 'Упор на локти и носки. Тело — прямая линия от головы до пяток. Напрягите пресс и ягодицы.', 'Провисание поясницы, подъём таза слишком высоко', 'Планка с колен', 'Планка с поочерёдным подъёмом ноги', 60),
  ('Выпады на месте', 'Шагните вперёд, опуститесь до прямого угла в обоих коленях. Спина прямая, колено не выходит за носок.', 'Колено выходит за носок, наклон корпуса', 'Уменьшите глубину выпада', 'Добавьте гантели или прыжок', 45),
  ('Тяга верхнего блока', 'Сядьте в тренажёр, возьмитесь за рукоять широким хватом. Тяните к верхней части груди, сводя лопатки.', 'Отклонение корпуса назад, тяга за счёт рук', 'Используйте меньший вес', 'Увеличьте вес или используйте узкий хват', 60),
  ('Жим ногами в тренажёре', 'Сядьте в тренажёр, поставьте стопы на ширине плеч. Опустите платформу, сгибая колени до 90°. Выжмите вверх.', 'Отрыв поясницы от спинки, полное выпрямление коленей', 'Используйте меньший вес', 'Жим одной ногой поочерёдно', 90),
  ('Разведение гантелей лёжа', 'Лягте на скамью, руки с гантелями вверху. Разведите руки в стороны, слегка сгибая локти. Сведите обратно.', 'Слишком прямые руки, чрезмерная амплитуда', 'Используйте лёгкие гантели', 'Выполняйте на наклонной скамье', 60),
  ('Гиперэкстензия', 'Зафиксируйте ноги в тренажёре. Опустите корпус вниз, затем поднимите до прямой линии с ногами.', 'Переразгибание в пояснице, рывки', 'Уменьшите амплитуду', 'Добавьте вес к груди', 60),
  ('Вращения плечами', 'Стойте прямо, выполняйте круговые движения плечами вперёд и назад с полной амплитудой.', 'Слишком быстрые движения', 'Выполняйте без дополнительного веса', 'Добавьте лёгкие гантели', 20),
